// Use the MongoDB aggregation framework with the $project operator to remove the embedded fields
function solve(documents, fieldsToIgnore) {
  const pipeline = [
    {'$project': {fieldsToIgnore: 0}}
  ];
  return documents.reduce((acc, doc) => {
    return acc.concat(doc);
  }, []);
}

